  "trivia": [
    {
      "id": "1994-final-on-penalties",
      "year": 1994,
      "category": "finals",
      "fact": "Brazil 0-0 Italy (3-2 pens) on 17 July 1994 in the Rose Bowl, Pasadena was the first World Cup final ever decided on penalties. Roberto Baggio missed the decisive kick — sending it over the bar. Brazil won their fourth title.",
      "players": [
        "Roberto Baggio"
      ],
      "teams": [
        "Brazil",
        "Italy"
      ]
    },
    {
      "id": "1994-salenko-five-goals",
      "year": 1994,
      "category": "records",
      "fact": "Russia's Oleg Salenko scored 5 goals in a single match — Russia 6-1 Cameroon, 28 June 1994 — the only player ever to do so at a World Cup. Russia were eliminated in the group stage; Salenko shared the Golden Boot with Hristo Stoichkov on 6 goals.",
      "players": [
        "Oleg Salenko"
      ],
      "teams": [
        "Russia",
        "Cameroon"
      ]
    },
    {
      "id": "1994-attendance-record",
      "year": 1994,
      "category": "records",
      "fact": "USA 1994 set the all-time WC attendance record: 3,587,538 fans (averaging 68,991/match) — a record that still stands more than 30 years later, even with WC expansions.",
      "teams": [
        "United States"
      ]
    },
    {
      "id": "1994-yashin-trophy",
      "year": 1994,
      "category": "firsts",
      "fact": "1994 was the first WC to award the Lev Yashin Trophy for Best Goalkeeper. Belgium's Michel Preud'homme was the inaugural winner. The trophy is named after the legendary Soviet keeper.",
      "players": [
        "Michel Preud'homme"
      ],
      "teams": [
        "Belgium"
      ]
    },
    {
      "id": "1994-escobar-tragedy",
      "year": 1994,
      "category": "context",
      "fact": "Colombian defender Andrés Escobar was murdered in Medellín on 2 July 1994, ten days after his own goal in Colombia's 2-1 loss to USA. The killing was widely linked to Colombian drug-trafficking betting interests; the gunman served 11 years.",
      "players": [
        "Andrés Escobar"
      ],
      "teams": [
        "Colombia"
      ]
    }
  ],
